import { takaro, data } from '@takaro/helpers';

async function main() {
    const { gameServerId, module: { userConfig } } = data;
    const { currencyReward, rewardMessage } = userConfig;

    const [{ data: { data: roles } }, { data: { data: players, meta } }, currencyNameSetting] = await Promise.all([
        takaro.role.roleControllerSearch({ extend: ['permissions'] }),
        takaro.playerOnGameserver.playerOnGameServerControllerSearch({
            filters: { gameServerId: [gameServerId], online: [true] },
            extend: rewardMessage ? ['player'] : []
        }),
        rewardMessage ? takaro.settings.settingsControllerGetOne('currencyName', gameServerId) : null
    ]);

    if (!meta.total) return;

    const PERM = 'PLAYTIME_CURRENCY_OVERRIDE';
    const roleAmounts = {};
    const roleNames = {};
    let maxReward = currencyReward;

    for (const { id, name, permissions } of roles) {
        if (permissions?.length) {
            for (const p of permissions) {
                if (p.permission?.permission === PERM && p.count > 0) {
                    roleAmounts[id] = p.count;
                    roleNames[id] = name;
                    if (p.count > maxReward) maxReward = p.count;
                    break;
                }
            }
        }
    }

    const currencyName = currencyNameSetting?.data?.data?.value || "coins";
    const rolePrefix = "having role ";

    await Promise.all(players.map(async (pog) => {
        let reward = currencyReward;
        let roleName = "being online";

        const playerRoles = pog.roles;
        if (playerRoles?.length) {
            for (let i = 0, len = playerRoles.length; i < len; i++) {
                const roleId = playerRoles[i].roleId;
                const amount = roleAmounts[roleId];
                if (amount > reward) {
                    reward = amount;
                    roleName = rolePrefix + roleNames[roleId];
                    if (reward === maxReward) break;
                }
            }
        }

        if (reward <= 0) return;

        if (rewardMessage) {
            await Promise.all([
                takaro.playerOnGameserver.playerOnGameServerControllerAddCurrency(gameServerId, pog.playerId, { currency: reward }),
                takaro.gameserver.gameServerControllerSendMessage(gameServerId, {
                    message: rewardMessage
                        .replace('{name}', pog.player?.name || 'Player')
                        .replace('{currency}', `${reward} ${currencyName}`)
                        .replace('{role}', roleName)
                })
            ]);
        } else {
            await takaro.playerOnGameserver.playerOnGameServerControllerAddCurrency(gameServerId, pog.playerId, { currency: reward });
        }
    }));
}

await main();
